--
-- Name: add_player_xp("uuid", integer); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION "public"."add_player_xp"("p_player_id" "uuid", "p_xp" integer) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  UPDATE profiles
  SET
    xp = xp + p_xp,
    level = calculate_level_from_xp(xp + p_xp)
  WHERE id = p_player_id;
END;
$$;


