--
-- Name: apply_seasonal_elo_reset(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION "public"."apply_seasonal_elo_reset"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  UPDATE public.profiles
  SET elo = ROUND(elo + 0.2 * (1500 - elo))::INTEGER;
END;
$$;


ALTER FUNCTION "public"."apply_seasonal_elo_reset"() OWNER TO "supabase_admin";

--
-- Name: assign_daily_quests("uuid"); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION "public"."assign_daily_quests"("p_player_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_count INTEGER;
BEGIN
    SELECT COUNT(*) INTO v_count FROM player_daily_quests 
    WHERE player_id = p_player_id AND assigned_date = CURRENT_DATE;

    IF v_count >= 3 THEN
        RETURN FALSE;
    END IF;

    INSERT INTO player_daily_quests (player_id, quest_id, assigned_date)
    SELECT p_player_id, id, CURRENT_DATE
    FROM quest_catalog
    WHERE is_active = TRUE 
      AND id NOT IN (
          SELECT quest_id FROM player_daily_quests 
          WHERE player_id = p_player_id AND assigned_date = CURRENT_DATE
      )
    ORDER BY random()
    LIMIT (3 - v_count)
    ON CONFLICT (player_id, quest_id, assigned_date) DO NOTHING;

    RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."assign_daily_quests"("p_player_id" "uuid") OWNER TO "supabase_admin";

--
-- Name: atomic_charge_coins("uuid", integer, "text", "uuid"); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION "public"."atomic_charge_coins"("p_player_id" "uuid", "p_amount" integer, "p_reason" "text", "p_ref_id" "uuid" DEFAULT NULL::"uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_coins INTEGER;
BEGIN
  -- Validar que el monto sea positivo
  IF p_amount <= 0 THEN
    RAISE EXCEPTION 'El monto a cobrar debe ser mayor a cero';
  END IF;

  -- Bloqueo de fila para evitar modificaciones concurrentes
  SELECT coins INTO v_coins
  FROM public.profiles
  WHERE id = p_player_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Perfil de jugador no encontrado';
  END IF;

  IF v_coins < p_amount THEN
    RETURN FALSE;
  END IF;

  UPDATE public.profiles
  SET coins = coins - p_amount
  WHERE id = p_player_id;

  INSERT INTO public.wallet_transactions (player_id, amount, reason, reference_id)
  VALUES (p_player_id, -p_amount, p_reason, p_ref_id);

  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."atomic_charge_coins"("p_player_id" "uuid", "p_amount" integer, "p_reason" "text", "p_ref_id" "uuid") OWNER TO "supabase_admin";

--
-- Name: atomic_refund_coins("uuid", integer, "text"); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION "public"."atomic_refund_coins"("p_player_id" "uuid", "p_amount" integer, "p_reason" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_exists BOOLEAN;
BEGIN
  -- Validar que el monto sea positivo
  IF p_amount <= 0 THEN
    RAISE EXCEPTION 'El monto a reembolsar debe ser mayor a cero';
  END IF;

  -- Verificar existencia del jugador
  SELECT EXISTS(SELECT 1 FROM public.profiles WHERE id = p_player_id) INTO v_exists;
  IF NOT v_exists THEN
    RAISE EXCEPTION 'Perfil de jugador no encontrado';
  END IF;

  UPDATE public.profiles
  SET coins = coins + p_amount
  WHERE id = p_player_id;

  INSERT INTO public.wallet_transactions (player_id, amount, reason, reference_id)
  VALUES (p_player_id, p_amount, p_reason, NULL);

  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."atomic_refund_coins"("p_player_id" "uuid", "p_amount" integer, "p_reason" "text") OWNER TO "supabase_admin";

--
-- Name: auto_accept_friend_request("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."auto_accept_friend_request"("p_user_id" "uuid", "p_other_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_request_id UUID;
BEGIN
  -- Validar que el actor coincida con p_user_id
  IF p_user_id != auth.uid() THEN
    RAISE EXCEPTION 'No autorizado: Identidad inválida.';
  END IF;

  SELECT id INTO v_request_id
  FROM public.friend_requests
  WHERE sender_id = p_other_id
    AND receiver_id = p_user_id
    AND status = 'pending'
  LIMIT 1;

  IF NOT FOUND THEN
    RETURN FALSE;
  END IF;

  PERFORM public.respond_friend_request(v_request_id, p_user_id, 'accepted');
  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."auto_accept_friend_request"("p_user_id" "uuid", "p_other_id" "uuid") OWNER TO "postgres";

--
-- Name: award_tournament_prize("uuid", "uuid", integer); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION "public"."award_tournament_prize"("event_id_param" "uuid", "winner_id_param" "uuid", "prize_amount" integer) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  -- Incrementar el contador de torneos ganados independientemente del premio
  UPDATE public.profiles 
  SET tournaments_won = tournaments_won + 1 
  WHERE id = winner_id_param;

  -- Procesar el premio en monedas si existe
  IF prize_amount > 0 THEN
    -- A??adir saldo
    UPDATE public.profiles SET coins = coins + prize_amount WHERE id = winner_id_param;
    
    -- Registrar transacci??n
    INSERT INTO public.wallet_transactions (player_id, amount, reason, reference_id) 
    VALUES (winner_id_param, prize_amount, 'tournament_prize', event_id_param);
  END IF;
  
  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."award_tournament_prize"("event_id_param" "uuid", "winner_id_param" "uuid", "prize_amount" integer) OWNER TO "supabase_admin";

--
-- Name: buy_store_item("uuid"); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION "public"."buy_store_item"("p_item_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_price INTEGER;
    v_coins INTEGER;
BEGIN
    -- Verificar si el art??culo existe y obtener precio
    SELECT price INTO v_price FROM public.store_items WHERE id = p_item_id AND is_active = TRUE;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Art??culo no disponible.';
    END IF;

    -- Verificar si ya lo tiene
    IF EXISTS (SELECT 1 FROM public.player_inventory WHERE player_id = auth.uid() AND item_id = p_item_id) THEN
        RAISE EXCEPTION 'Ya posees este art??culo.';
    END IF;

    -- Obtener monedas del jugador
    SELECT coins INTO v_coins FROM public.profiles WHERE id = auth.uid();
    IF v_coins IS NULL OR v_coins < v_price THEN
        RAISE EXCEPTION 'Monedas insuficientes.';
    END IF;

    -- Descontar monedas
    UPDATE public.profiles SET coins = coins - v_price WHERE id = auth.uid();

    -- A??adir al inventario
    INSERT INTO public.player_inventory (player_id, item_id) VALUES (auth.uid(), p_item_id);

    -- Registrar transacci??n (si existe wallet_transactions)
    BEGIN
        INSERT INTO public.wallet_transactions (player_id, amount, reason)
        VALUES (auth.uid(), -v_price, 'store_purchase');
    EXCEPTION WHEN undefined_table THEN
        -- Ignorar si no existe
    END;

    RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."buy_store_item"("p_item_id" "uuid") OWNER TO "supabase_admin";

--
-- Name: calculate_level_from_xp(integer); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION "public"."calculate_level_from_xp"("p_xp" integer) RETURNS integer
    LANGUAGE "plpgsql" IMMUTABLE
    AS $$
DECLARE
  v_level INTEGER := 1;
  v_xp_needed INTEGER;
BEGIN
  LOOP
    v_xp_needed := v_level * 100;
    IF p_xp < v_xp_needed THEN
      RETURN v_level;
    END IF;
    p_xp := p_xp - v_xp_needed;
    v_level := v_level + 1;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."calculate_level_from_xp"("p_xp" integer) OWNER TO "supabase_admin";

--
-- Name: claim_quest_reward("uuid"); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION "public"."claim_quest_reward"("p_player_quest_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_player_id UUID;
    v_is_completed BOOLEAN;
    v_is_claimed BOOLEAN;
    v_reward_coins INTEGER;
    v_reward_xp INTEGER;
    v_reward_elo INTEGER;
BEGIN
    -- 1. Obtener la misi??n y validar (Incluimos reward_elo)
    SELECT pq.player_id, pq.is_completed, pq.is_claimed, qc.reward_coins, qc.reward_xp, qc.reward_elo
    INTO v_player_id, v_is_completed, v_is_claimed, v_reward_coins, v_reward_xp, v_reward_elo
    FROM player_daily_quests pq
    JOIN quest_catalog qc ON pq.quest_id = qc.id
    WHERE pq.id = p_player_quest_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Misi??n no encontrada.';
    END IF;

    -- Verificar que el que llama es el due??o
    IF v_player_id != auth.uid() THEN
        RAISE EXCEPTION 'No tienes permiso para reclamar esta misi??n.';
    END IF;

    IF NOT v_is_completed THEN
        RAISE EXCEPTION 'La misi??n a??n no est?? completada.';
    END IF;

    IF v_is_claimed THEN
        RAISE EXCEPTION 'La recompensa ya fue reclamada.';
    END IF;

    -- 2. Marcar como reclamada
    UPDATE player_daily_quests SET is_claimed = TRUE WHERE id = p_player_quest_id;

    -- 3. Entregar recompensas (coins, xp, elo)
    UPDATE profiles 
    SET 
        coins = COALESCE(coins, 0) + v_reward_coins,
        elo = COALESCE(elo, 1000) + v_reward_elo
    WHERE id = v_player_id;

    -- Registrar transacci??n en wallet si existe
    BEGIN
        INSERT INTO wallet_transactions (player_id, amount, reason)
        VALUES (v_player_id, v_reward_coins, 'quest_reward');
    EXCEPTION WHEN undefined_table THEN
        -- Ignorar si la tabla no existe
    END;

    RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."claim_quest_reward"("p_player_quest_id" "uuid") OWNER TO "supabase_admin";

--
-- Name: claim_rewarded_ad_coins(integer); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION "public"."claim_rewarded_ad_coins"("p_reward_amount" integer) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_user_id UUID;
  v_on_cooldown BOOLEAN;
  v_config_id UUID;
  v_new_coins INT;
  v_daily_count INT;
BEGIN
  -- 1. Verificar autenticación del usuario
  v_user_id := auth.uid();
  IF v_user_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'UNAUTHORIZED');
  END IF;

  -- 2. Validar cantidad de recompensa (máximo 1000 monedas por anuncio)
  IF p_reward_amount IS NULL OR p_reward_amount <= 0 OR p_reward_amount > 1000 THEN
    RETURN jsonb_build_object('success', false, 'error', 'INVALID_AMOUNT');
  END IF;

  -- 3. Verificar límite diario de 3 anuncios
  SELECT COUNT(1) INTO v_daily_count
  FROM public.ad_logs
  WHERE user_id = v_user_id
    AND ad_type = 'rewarded'
    AND event_type = 'complete'
    AND (metadata->>'rpc_claimed')::boolean = true
    AND created_at >= (NOW() AT TIME ZONE 'utc')::date;

  IF v_daily_count >= 3 THEN
    RETURN jsonb_build_object('success', false, 'error', 'DAILY_LIMIT_REACHED');
  END IF;

  -- 4. Verificar Cooldown de 55 segundos contra abusos de scripts (comprobando logs con rpc_claimed = true)
  SELECT EXISTS (
    SELECT 1 FROM public.ad_logs
    WHERE user_id = v_user_id
      AND ad_type = 'rewarded'
      AND event_type = 'complete'
      AND (metadata->>'rpc_claimed')::boolean = true
      AND created_at > NOW() - INTERVAL '55 seconds'
  ) INTO v_on_cooldown;

  IF v_on_cooldown THEN
    RETURN jsonb_build_object('success', false, 'error', 'ON_COOLDOWN');
  END IF;

  -- 5. Obtener la configuración de anuncio recompensado activa para asociar el log
  SELECT id INTO v_config_id 
  FROM public.ad_configurations
  WHERE ad_type = 'rewarded' AND enabled = true
  ORDER BY priority ASC 
  LIMIT 1;

  -- 6. Actualizar el saldo de monedas en la tabla profiles
  UPDATE public.profiles
  SET coins = coins + p_reward_amount
  WHERE id = v_user_id
  RETURNING coins INTO v_new_coins;

  -- 7. Insertar el log de finalización en el servidor de forma atómica
  INSERT INTO public.ad_logs (config_id, ad_type, event_type, user_id, metadata)
  VALUES (
    v_config_id,
    'rewarded',
    'complete',
    v_user_id,
    jsonb_build_object('coins_rewarded', p_reward_amount, 'rpc_claimed', true)
  );

  RETURN jsonb_build_object('success', true, 'new_coins', v_new_coins);
END;
$$;


ALTER FUNCTION "public"."claim_rewarded_ad_coins"("p_reward_amount" integer) OWNER TO "supabase_admin";

--
-- Name: cleanup_expired_invitations(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."cleanup_expired_invitations"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_updated INTEGER;
BEGIN
  UPDATE game_invitations
  SET status = 'expired'
  WHERE status = 'pending' AND expires_at < NOW();

  GET DIAGNOSTICS v_updated = ROW_COUNT;
  RETURN v_updated;
END;
$$;


ALTER FUNCTION "public"."cleanup_expired_invitations"() OWNER TO "postgres";

--
-- Name: cleanup_old_notifications(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."cleanup_old_notifications"("p_days" integer DEFAULT 30) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_deleted INTEGER;
BEGIN
  DELETE FROM notifications
  WHERE is_read = TRUE
    AND created_at < NOW() - (p_days || ' days')::INTERVAL;

  GET DIAGNOSTICS v_deleted = ROW_COUNT;
  RETURN v_deleted;
END;
$$;


ALTER FUNCTION "public"."cleanup_old_notifications"("p_days" integer) OWNER TO "postgres";

--
-- Name: create_notification("uuid", "text", "text", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."create_notification"("p_player_id" "uuid", "p_type" "text", "p_content" "text", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_id UUID;
  v_allowed_types TEXT[] := ARRAY[
    'friend_request', 'game_invitation', 'tournament_start',
    'round_ready', 'achievement', 'level_up', 'division_change'
  ];
BEGIN
  IF NOT (p_type = ANY(v_allowed_types)) THEN
    RAISE EXCEPTION 'Tipo de notificaci??n inv??lido: %', p_type;
  END IF;

  IF NOT EXISTS (SELECT 1 FROM profiles WHERE id = p_player_id) THEN
    RAISE EXCEPTION 'El jugador % no existe', p_player_id;
  END IF;

  INSERT INTO notifications (player_id, type, content, metadata)
  VALUES (p_player_id, p_type, p_content, p_metadata)
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."create_notification"("p_player_id" "uuid", "p_type" "text", "p_content" "text", "p_metadata" "jsonb") OWNER TO "postgres";

--
-- Name: delete_notification("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."delete_notification"("p_notification_id" "uuid", "p_player_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF p_player_id != auth.uid() THEN
    RAISE EXCEPTION 'No autorizado: Identidad inválida.';
  END IF;

  DELETE FROM public.notifications
  WHERE id = p_notification_id AND player_id = p_player_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Notificación no encontrada o no pertenece al jugador';
  END IF;
END;
$$;


ALTER FUNCTION "public"."delete_notification"("p_notification_id" "uuid", "p_player_id" "uuid") OWNER TO "postgres";

