--
-- Name: equip_store_item("uuid", integer); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION "public"."equip_store_item"("p_item_id" "uuid", "p_slot" integer DEFAULT 1) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_item_type TEXT;
    v_image_url TEXT;
    v_item_name TEXT;
    v_theme_key TEXT;
    v_current_emotics TEXT[];
BEGIN
    -- 1. Verify ownership
    IF NOT EXISTS (
        SELECT 1 FROM public.player_inventory 
        WHERE player_id = auth.uid() AND item_id = p_item_id
    ) THEN
        RAISE EXCEPTION 'No posees este art??culo.';
    END IF;

    -- 2. Get item info
    SELECT item_type, image_url, "name", theme_key
    INTO v_item_type, v_image_url, v_item_name, v_theme_key
    FROM public.store_items 
    WHERE id = p_item_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Art??culo no encontrado.';
    END IF;

    -- 3. Update profile based on type
    IF v_item_type = 'avatar' THEN
        UPDATE public.profiles SET equipped_avatar = v_image_url WHERE id = auth.uid();
    ELSIF v_item_type = 'title' THEN
        UPDATE public.profiles SET equipped_title = v_item_name WHERE id = auth.uid();
    ELSIF v_item_type = 'board' THEN
        UPDATE public.profiles SET equipped_board = v_image_url WHERE id = auth.uid();
    ELSIF v_item_type = 'theme' THEN
        UPDATE public.profiles SET equipped_theme = v_theme_key WHERE id = auth.uid();
    ELSIF v_item_type = 'emotic' THEN
        -- Slot logic for emotics (1 to 4)
        IF p_slot < 1 OR p_slot > 4 THEN
            RAISE EXCEPTION 'El slot debe estar entre 1 y 4.';
        END IF;

        -- Get current emotics array
        SELECT equipped_emotics INTO v_current_emotics FROM public.profiles WHERE id = auth.uid();

        -- Ensure array is initialized
        IF v_current_emotics IS NULL THEN
            v_current_emotics := ARRAY['????', '????', '????', '????']::TEXT[];
        END IF;

        -- Pad array if smaller than requested slot
        WHILE array_length(v_current_emotics, 1) < p_slot LOOP
            v_current_emotics := array_append(v_current_emotics, '????');
        END LOOP;

        -- Update specific slot
        v_current_emotics[p_slot] := v_image_url;

        UPDATE public.profiles SET equipped_emotics = v_current_emotics WHERE id = auth.uid();
    ELSE
        RAISE EXCEPTION 'Tipo de art??culo desconocido: %', v_item_type;
    END IF;

    RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."equip_store_item"("p_item_id" "uuid", "p_slot" integer) OWNER TO "supabase_admin";

--
-- Name: get_daily_rewarded_ad_count(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION "public"."get_daily_rewarded_ad_count"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_user_id UUID;
  v_count INT;
BEGIN
  v_user_id := auth.uid();
  IF v_user_id IS NULL THEN
    RETURN 0;
  END IF;

  SELECT COUNT(1) INTO v_count
  FROM public.ad_logs
  WHERE user_id = v_user_id
    AND ad_type = 'rewarded'
    AND event_type = 'complete'
    AND (metadata->>'rpc_claimed')::boolean = true
    AND created_at >= (NOW() AT TIME ZONE 'utc')::date;

  RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."get_daily_rewarded_ad_count"() OWNER TO "supabase_admin";

--
-- Name: get_player_division(integer); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION "public"."get_player_division"("player_elo" integer) RETURNS "text"
    LANGUAGE "plpgsql" IMMUTABLE
    AS $$
BEGIN
  IF    player_elo < 1200 THEN RETURN 'bronze';
  ELSIF player_elo < 1500 THEN RETURN 'silver';
  ELSIF player_elo < 1800 THEN RETURN 'gold';
  ELSIF player_elo < 2100 THEN RETURN 'platinum';
  ELSE                         RETURN 'diamond';
  END IF;
END;
$$;


ALTER FUNCTION "public"."get_player_division"("player_elo" integer) OWNER TO "supabase_admin";

--
-- Name: handle_new_user(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION "public"."handle_new_user"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  base_username TEXT;
  final_username TEXT;
  user_avatar TEXT;
  counter INTEGER := 1;
  max_attempts INTEGER := 10;
BEGIN
  -- Extraer nombre base dependiendo de los metadatos disponibles (Email, Google, Discord)
  base_username := COALESCE(
    new.raw_user_meta_data->>'username',           -- Email signup tradicional
    new.raw_user_meta_data#>>'{custom_claims,global_name}', -- Discord
    new.raw_user_meta_data->>'full_name',          -- Google
    new.raw_user_meta_data->>'name',               -- Otros proveedores
    'Jugador'                                      -- Fallback
  );

  -- Limpiar el nombre de usuario (quitar espacios en blanco, etc.)
  base_username := trim(base_username);
  
  -- Si el nombre está vacío después de limpiar, usar fallback
  IF base_username = '' THEN
    base_username := 'Jugador';
  END IF;

  -- Inicializar el nombre final con el base
  final_username := base_username;

  -- Bucle para encontrar un nombre de usuario único
  WHILE EXISTS (SELECT 1 FROM public.profiles WHERE username = final_username) AND counter <= max_attempts LOOP
    -- Si el nombre ya existe, agregar un sufijo aleatorio de 4 dígitos
    final_username := base_username || '_' || floor(random() * 9000 + 1000)::TEXT;
    counter := counter + 1;
  END LOOP;

  -- Si después de 10 intentos (muy improbable) sigue habiendo colisión, usar el UUID
  IF EXISTS (SELECT 1 FROM public.profiles WHERE username = final_username) THEN
    final_username := 'Jugador_' || substr(new.id::TEXT, 1, 8);
  END IF;

  -- Extraer avatar URL si está disponible
  user_avatar := COALESCE(
    new.raw_user_meta_data->>'avatar_url',
    new.raw_user_meta_data->>'picture',
    NULL
  );

  BEGIN
    INSERT INTO public.profiles (id, username, avatar_url)
    VALUES (new.id, final_username, user_avatar)
    ON CONFLICT (id) DO NOTHING;
  EXCEPTION WHEN unique_violation THEN
    -- Ocurrió una colisión de username por race condition entre
    -- transacciones concurrentes. Reintentar con UUID como fallback.
    INSERT INTO public.profiles (id, username, avatar_url)
    VALUES (new.id, 'Jugador_' || substr(new.id::TEXT, 1, 8), user_avatar)
    ON CONFLICT (id) DO NOTHING;
  END;

  RETURN new;
END;
$$;


ALTER FUNCTION "public"."handle_new_user"() OWNER TO "supabase_admin";

--
-- Name: increment_quest_progress("uuid", "text"); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION "public"."increment_quest_progress"("p_player_id" "uuid", "p_quest_type" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_quest RECORD;
BEGIN
  FOR v_quest IN 
    SELECT pdq.id as player_quest_id, pdq.progress, qc.target_amount
    FROM public.player_daily_quests pdq
    JOIN public.quest_catalog qc ON pdq.quest_id = qc.id
    WHERE pdq.player_id = p_player_id 
      AND pdq.assigned_date = CURRENT_DATE
      AND pdq.is_completed = false
      AND qc.quest_type = p_quest_type
  LOOP
    UPDATE public.player_daily_quests
    SET 
      progress = LEAST(progress + 1, v_quest.target_amount),
      is_completed = CASE WHEN (progress + 1) >= v_quest.target_amount THEN true ELSE false END,
      updated_at = NOW()
    WHERE id = v_quest.player_quest_id;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."increment_quest_progress"("p_player_id" "uuid", "p_quest_type" "text") OWNER TO "supabase_admin";

--
-- Name: join_event("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION "public"."join_event"("event_id_param" "uuid", "player_id_param" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_fee INTEGER;
  v_coins INTEGER;
  v_status TEXT;
  v_participants_count INTEGER;
  v_max_participants INTEGER;
  v_already_enrolled BOOLEAN;
BEGIN
  -- Validar que el actor coincida con el usuario autenticado
  IF player_id_param != auth.uid() THEN
    RAISE EXCEPTION 'No autorizado: No puedes inscribir a otro jugador.';
  END IF;

  -- 1. Validar que el evento existe y obtener datos
  SELECT entry_fee, status, participants_count, max_participants 
  INTO v_fee, v_status, v_participants_count, v_max_participants 
  FROM public.events WHERE id = event_id_param;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'El evento no existe';
  END IF;

  -- 2. Validar estado del evento
  IF v_status != 'upcoming' THEN
    RAISE EXCEPTION 'El evento no está abierto para inscripciones';
  END IF;

  -- 3. Validar cupo
  IF v_participants_count >= v_max_participants THEN
    RAISE EXCEPTION 'El evento está lleno';
  END IF;

  -- 4. Validar si ya está inscrito
  SELECT EXISTS(SELECT 1 FROM public.event_entries WHERE event_id = event_id_param AND player_id = player_id_param) INTO v_already_enrolled;
  IF v_already_enrolled THEN
    RAISE EXCEPTION 'Ya estás inscrito en este evento';
  END IF;

  -- 5. Obtener saldo actual con FOR UPDATE para evitar race condition
  SELECT coins INTO v_coins FROM public.profiles WHERE id = player_id_param FOR UPDATE;

  -- 6. Validar saldo
  IF v_coins < v_fee THEN
    RAISE EXCEPTION 'Saldo insuficiente';
  END IF;

  -- 7. Deducir saldo
  IF v_fee > 0 THEN
    UPDATE public.profiles SET coins = coins - v_fee WHERE id = player_id_param;
    
    -- Registrar transacción
    INSERT INTO public.wallet_transactions (player_id, amount, reason, reference_id) 
    VALUES (player_id_param, -v_fee, 'tournament_entry', event_id_param);
  END IF;

  -- 8. Inscribir jugador
  INSERT INTO public.event_entries (event_id, player_id) VALUES (event_id_param, player_id_param);

  -- 9. Actualizar contador de participantes
  UPDATE public.events SET participants_count = participants_count + 1 WHERE id = event_id_param;

  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."join_event"("event_id_param" "uuid", "player_id_param" "uuid") OWNER TO "supabase_admin";

