-- Name: notify_friend_request_accepted(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."notify_friend_request_accepted"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_receiver_name TEXT;
BEGIN
  SELECT COALESCE(username, 'Un jugador') INTO v_receiver_name
  FROM profiles WHERE id = NEW.receiver_id;

  PERFORM create_notification(
    NEW.sender_id,
    'friend_request',
    v_receiver_name || ' acept?? tu solicitud de amistad.',
    jsonb_build_object(
      'receiver_id', NEW.receiver_id,
      'receiver_name', v_receiver_name,
      'request_id', NEW.id
    )
  );

  RETURN NEW;
END;
$$;


