--
-- Name: process_match_results("text", "text", "uuid", boolean, "jsonb"); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION "public"."process_match_results"("p_room_id" "text", "p_game_mode" "text", "p_winner_id" "uuid", "p_is_tournament" boolean, "p_players_data" "jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_player JSONB;
  v_player_id UUID;
  v_is_winner BOOLEAN;
  v_elo_change INTEGER;
  v_coins_earned INTEGER;
  v_xp_gained INTEGER;
  v_score INTEGER;
  v_name TEXT;
  v_metadata JSONB := '[]'::JSONB;
BEGIN
  FOR v_player IN SELECT * FROM jsonb_array_elements(p_players_data)
  LOOP
    v_player_id := (v_player->>'id')::UUID;
    v_is_winner := (v_player->>'is_winner')::BOOLEAN;
    v_elo_change := (v_player->>'elo_change')::INTEGER;
    v_coins_earned := (v_player->>'coins_earned')::INTEGER;
    v_xp_gained := (v_player->>'xp_gained')::INTEGER;
    v_score := (v_player->>'score')::INTEGER;
    v_name := v_player->>'name';

    UPDATE public.profiles
    SET
      coins = coins + v_coins_earned,
      elo = elo + v_elo_change,
      wins = wins + CASE WHEN v_is_winner THEN 1 ELSE 0 END,
      losses = losses + CASE WHEN v_is_winner THEN 0 ELSE 1 END
    WHERE id = v_player_id;

    IF v_coins_earned > 0 THEN
      INSERT INTO public.wallet_transactions (player_id, amount, reason)
      VALUES (v_player_id, v_coins_earned, 'Match Prize: ' || p_room_id);
    END IF;

    PERFORM public.add_player_xp(v_player_id, v_xp_gained);
    PERFORM public.increment_quest_progress(v_player_id, 'play_match');
    IF v_is_winner THEN
      PERFORM public.increment_quest_progress(v_player_id, 'win_match');
    END IF;

    v_metadata := v_metadata || jsonb_build_object(
      'id', v_player_id,
      'name', v_name,
      'score', v_score,
      'elo_change', v_elo_change,
      'coins_earned', v_coins_earned
    );
  END LOOP;

  INSERT INTO public.match_history (game_mode, winner_id, metadata)
  VALUES (
    CASE WHEN p_is_tournament THEN 'tournament' ELSE p_game_mode END,
    p_winner_id,
    v_metadata
  );
END;
$$;


ALTER FUNCTION "public"."process_match_results"("p_room_id" "text", "p_game_mode" "text", "p_winner_id" "uuid", "p_is_tournament" boolean, "p_players_data" "jsonb") OWNER TO "supabase_admin";

--
-- Name: resend_friend_request("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."resend_friend_request"("p_sender_id" "uuid", "p_receiver_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_existing_id UUID;
  v_existing_status TEXT;
  v_new_id UUID;
BEGIN
  -- Validar que el actor coincida con el sender
  IF p_sender_id != auth.uid() THEN
    RAISE EXCEPTION 'No autorizado: Identidad inválida.';
  END IF;

  -- Buscar solicitud existente
  SELECT id, status
  INTO v_existing_id, v_existing_status
  FROM public.friend_requests
  WHERE sender_id = p_sender_id AND receiver_id = p_receiver_id;

  IF FOUND THEN
    IF v_existing_status = 'pending' THEN
      RAISE EXCEPTION 'Ya tienes una solicitud pendiente con este jugador';
    ELSIF v_existing_status = 'accepted' THEN
      RAISE EXCEPTION 'Ya son amigos';
    END IF;

    UPDATE public.friend_requests
    SET status = 'pending',
        responded_at = NULL,
        created_at = NOW()
    WHERE id = v_existing_id;

    RETURN v_existing_id;
  ELSE
    INSERT INTO public.friend_requests (sender_id, receiver_id, status)
    VALUES (p_sender_id, p_receiver_id, 'pending')
    RETURNING id INTO v_new_id;

    RETURN v_new_id;
  END IF;
END;
$$;


ALTER FUNCTION "public"."resend_friend_request"("p_sender_id" "uuid", "p_receiver_id" "uuid") OWNER TO "postgres";

--
-- Name: respond_friend_request("uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."respond_friend_request"("p_request_id" "uuid", "p_user_id" "uuid", "p_action" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_sender_id UUID;
  v_receiver_id UUID;
  v_current_status TEXT;
BEGIN
  -- Validar que el usuario autenticado coincida con el argumento
  IF p_user_id != auth.uid() THEN
    RAISE EXCEPTION 'No autorizado: Identidad inválida.';
  END IF;

  -- Validar acción
  IF p_action NOT IN ('accepted', 'rejected') THEN
    RAISE EXCEPTION 'Acción inválida. Use accepted o rejected.';
  END IF;

  -- Obtener datos de la solicitud
  SELECT sender_id, receiver_id, status
  INTO v_sender_id, v_receiver_id, v_current_status
  FROM public.friend_requests
  WHERE id = p_request_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Solicitud de amistad no encontrada';
  END IF;

  -- Verificar que el usuario sea el receptor
  IF v_receiver_id != p_user_id THEN
    RAISE EXCEPTION 'Solo el receptor puede responder a esta solicitud';
  END IF;

  -- Verificar que esté pendiente
  IF v_current_status != 'pending' THEN
    RAISE EXCEPTION 'La solicitud ya fue respondida (estado actual: %)', v_current_status;
  END IF;

  -- Actualizar estado
  UPDATE public.friend_requests
  SET status = p_action,
      responded_at = NOW()
  WHERE id = p_request_id;

  -- Si se acepta, crear registro en friendships
  IF p_action = 'accepted' THEN
    INSERT INTO public.friendships (player1_id, player2_id, status)
    VALUES (
      LEAST(v_sender_id, v_receiver_id),
      GREATEST(v_sender_id, v_receiver_id),
      'accepted'
    )
    ON CONFLICT (player1_id, player2_id) DO NOTHING;
  END IF;

  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."respond_friend_request"("p_request_id" "uuid", "p_user_id" "uuid", "p_action" "text") OWNER TO "postgres";

