--
-- Name: update_peak_elo(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION "public"."update_peak_elo"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
    IF NEW.elo > OLD.peak_elo THEN
        NEW.peak_elo := NEW.elo;
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."update_peak_elo"() OWNER TO "supabase_admin";

--
-- Name: update_player_stats("uuid", boolean, integer); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION "public"."update_player_stats"("p_player_id" "uuid", "p_is_winner" boolean, "p_elo_change" integer) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  UPDATE public.profiles
  SET
    elo    = elo + p_elo_change,
    wins   = wins   + CASE WHEN p_is_winner THEN 1 ELSE 0 END,
    losses = losses + CASE WHEN p_is_winner THEN 0 ELSE 1 END
  WHERE id = p_player_id;
END;
$$;


